import{c as n}from"./app.8935f5f1.js";const e={},r=n('<div class="language-conf ext-conf"><pre class="language-conf"><code># 负载均衡\n\t upstream luisfer{\n\t\tserver 192.168.1.101:8080 weight=5;\n\t\tserver 192.168.1.102:8080 weight=5;\n\t }\n\n\n  location / {\n   \n        root   /app/hoom/ui/dist;  # node js  静态文件\n        index  index.html index.htm;\n\n  }\n\n location /prod-api/ {\n      proxy_http_version 1.1;\n      proxy_set_header X-Real-IP $remote_addr;\n      proxy_set_header X-Forwarded-For $proxy_add_x_forwarded_for;\n      proxy_set_header Host $http_host;\n      proxy_set_header X-NginX-Proxy true;\n      proxy_set_header Upgrade $http_upgrade;\n      proxy_set_header Connection &quot;upgrade&quot;;\n\n      proxy_pass http://127.0.0.1:8080/;\n                            # 结尾 带 /  请求不加 location prod-api\n                            # 结尾 无 /  请求=》  http://127.0.0.1:8080/prod-api\n\n      proxy_pass http://luisfer/;  #负载均衡，配合 upstream\n\n      #proxy_pass http://127.0.0.1:$node_port$request_uri;\n\n      proxy_redirect off;\n  }\n\n\n\n\n\n</code></pre></div><h3 id="路径匹配细节" tabindex="-1"><a class="header-anchor" href="#路径匹配细节" aria-hidden="true">#</a> 路径匹配细节</h3><p><a href="/os/nginx/README">参考开篇</a></p><div class="language-conf ext-conf"><pre class="language-conf"><code>\nupstream lusifer {\n      server 192.168.1.60:8881;\n      server 192.168.1.60:8882;\n\n}\n\nserver {\n      listen       80;\n      server_name  localhost;\n\n      location /api {\n            proxy_pass http://lusifer/;\n            # proxy_pass http://lusifer;  匹配\n            # proxy_pass http://lusifer/;\n      }\n}\n</code></pre></div>',4);e.render=function(n,e){return r};export{e as default};
